import{bQ as d,aL as e,u as a,G as s}from"./chunks/framework.D06dwy5q.js";const b=JSON.parse('{"title":"网络基础","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/12-网络基础.md","filePath":"01.Linux基础/12-网络基础.md","lastUpdated":null}'),o={name:"01.Linux基础/12-网络基础.md"};function i(h,t,c,p,n,l){return e(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="网络基础" tabindex="-1">网络基础 <a class="header-anchor" href="#网络基础" aria-label="Permalink to &quot;网络基础&quot;">​</a></h1><p>Linux 网络排错离不开几个核心概念：IP 地址、子网掩码、网关、DNS、端口和 TCP 连接。这些概念决定后面所有网络配置和诊断命令的用法。</p><h2 id="一、ip-地址" tabindex="-1">一、IP 地址 <a class="header-anchor" href="#一、ip-地址" aria-label="Permalink to &quot;一、IP 地址&quot;">​</a></h2><p>IP 地址是主机在网络中的地址标识。Linux 上一个网卡可以绑定一个或多个 IP 地址，服务监听时可以选择只监听某个特定的 IP，也可以监听所有地址。</p><p>IPv4 地址是 32 位，通常写成点分十进制：<code>192.168.1.10</code>。</p><p>按使用范围分为公有地址和私有地址。私有地址只能在局域网或内网中使用，不能直接在公网上路由。</p><p>私有地址范围：</p><table tabindex="0"><thead><tr><th>网段</th><th>范围</th></tr></thead><tbody><tr><td><code>10.0.0.0/8</code></td><td>10.0.0.0 — 10.255.255.255</td></tr><tr><td><code>172.16.0.0/12</code></td><td>172.16.0.0 — 172.31.255.255</td></tr><tr><td><code>192.168.0.0/16</code></td><td>192.168.0.0 — 192.168.255.255</td></tr></tbody></table><p>服务器内网通信通常都在这些网段内。几个特殊地址：</p><table tabindex="0"><thead><tr><th>地址</th><th>含义</th></tr></thead><tbody><tr><td><code>127.0.0.1</code></td><td>本机回环地址（localhost），只能本机访问</td></tr><tr><td><code>0.0.0.0</code></td><td>监听时表示&quot;本机所有 IPv4 地址&quot;</td></tr><tr><td><code>::1</code></td><td>IPv6 的回环地址</td></tr></tbody></table><p>服务如果只监听 <code>127.0.0.1:8080</code>，同机 curl 没问题，但外部机器无法访问——即使防火墙全放也不行。排查&quot;服务启动了但外部访问不了&quot;时，第一眼就看监听地址是不是 <code>127.0.0.1</code>。</p><h2 id="二、子网掩码和-cidr" tabindex="-1">二、子网掩码和 CIDR <a class="header-anchor" href="#二、子网掩码和-cidr" aria-label="Permalink to &quot;二、子网掩码和 CIDR&quot;">​</a></h2><p>子网掩码用来区分 IP 地址中的&quot;网络部分&quot;和&quot;主机部分&quot;。同一个网段内，网络部分相同，主机可以直接通信。不同网段的数据要经过网关转发。</p><p>CIDR（无类别域间路由）写法把掩码长度直接附在 IP 后面：<code>192.168.1.10/24</code>。<code>/24</code> 表示前 24 位是网络位，剩下 8 位是主机位。</p><p><code>192.168.1.10/24</code> 所在网段：</p><ul><li>网络地址：<code>192.168.1.0</code></li><li>可用主机范围：<code>192.168.1.1</code> — <code>192.168.1.254</code></li><li>广播地址：<code>192.168.1.255</code></li></ul><p>常见 CIDR 对照：</p><table tabindex="0"><thead><tr><th>CIDR</th><th>子网掩码</th><th>可用主机数</th></tr></thead><tbody><tr><td><code>/24</code></td><td>255.255.255.0</td><td>254</td></tr><tr><td><code>/25</code></td><td>255.255.255.128</td><td>126</td></tr><tr><td><code>/26</code></td><td>255.255.255.192</td><td>62</td></tr><tr><td><code>/16</code></td><td>255.255.0.0</td><td>65534</td></tr></tbody></table><p>两台机器是否属于同一网段，不是看 IP 地址是否相近，而是看 IP 和掩码一起计算出的网络地址是否相同。同一个 IP 配上不同的掩码，归属的网段可能完全不同。</p><table tabindex="0"><thead><tr><th>IP</th><th>掩码</th><th>网段</th></tr></thead><tbody><tr><td><code>192.168.1.200</code></td><td><code>/24</code></td><td><code>192.168.1.0/24</code></td></tr><tr><td><code>192.168.1.200</code></td><td><code>/25</code></td><td><code>192.168.1.128/25</code></td></tr></tbody></table><p>云主机上修改网卡配置时，掩码填错会导致&quot;IP 看着正确，但就是不通&quot;。</p><h2 id="三、网关" tabindex="-1">三、网关 <a class="header-anchor" href="#三、网关" aria-label="Permalink to &quot;三、网关&quot;">​</a></h2><p>默认网关是内网主机通往外部网络的出口。访问不在本网段的地址时，数据包发给默认网关，由网关负责转发。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span></span></code></pre></div><p>输出示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>default via 192.168.1.1 dev eth0</span></span>
<span class="line"><span>192.168.1.0/24 dev eth0 proto kernel scope link src 192.168.1.10</span></span></code></pre></div><p>第一行：所有目的地不在路由表中的流量（default），都从 <code>eth0</code> 发给下一跳 <code>192.168.1.1</code>。</p><p>第二行：<code>192.168.1.0/24</code> 这个直连网段的流量，直接从 <code>eth0</code> 出去，源地址为 <code>192.168.1.10</code>。</p><p>路由匹配遵循&quot;最长前缀优先&quot;原则：去往 <code>10.10.1.2</code> 的包，如果路由表中同时有 <code>10.0.0.0/8</code> 和 <code>10.10.0.0/16</code>，会匹配更具体的 <code>/16</code>。</p><h2 id="四、dns" tabindex="-1">四、DNS <a class="header-anchor" href="#四、dns" aria-label="Permalink to &quot;四、DNS&quot;">​</a></h2><p>DNS 把人类可读的域名翻译成 IP 地址。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/resolv.conf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 查看当前使用的 DNS 服务器</span></span></code></pre></div><p>Linux 的域名解析顺序由 <code>/etc/nsswitch.conf</code> 中的 <code>hosts</code> 行控制：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^hosts:&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/nsswitch.conf</span></span></code></pre></div><p>输出示例：<code>hosts: files dns</code>——表示先查 <code>/etc/hosts</code>，再查 DNS。</p><p>线上出现过&quot;DNS 明明已经改了，但机器还解析到旧 IP&quot;的情况，最后发现 <code>/etc/hosts</code> 里写死了一个旧地址。排查域名解析异常时，<code>/etc/hosts</code> 和 <code>nsswitch.conf</code> 要一起看。</p><p>解析域名：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hosts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 走系统 NSS，模拟真实解析路径</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 直接查 DNS，绕过 hosts 和缓存</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @8.8.8.8</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 指定 DNS 服务器查询</span></span></code></pre></div><p><code>getent hosts</code> 的解析路径更接近应用程序实际使用的路径——包括 <code>/etc/hosts</code>、DNS、LDAP 等，取决于 nsswitch 配置。</p><h2 id="五、端口" tabindex="-1">五、端口 <a class="header-anchor" href="#五、端口" aria-label="Permalink to &quot;五、端口&quot;">​</a></h2><p>端口是传输层（TCP/UDP）用来区分不同服务的编号。同一个 IP 地址上可以同时运行 HTTP（80）、SSH（22）、MySQL（3306）等多个服务，靠端口号区别。</p><p>端口范围：</p><table tabindex="0"><thead><tr><th>范围</th><th>分类</th></tr></thead><tbody><tr><td>0-1023</td><td>知名端口（Well-known），需要 root 权限绑定</td></tr><tr><td>1024-49151</td><td>注册端口</td></tr><tr><td>49152-65535</td><td>临时/私有端口，客户端通常从这个范围随机选取</td></tr></tbody></table><p>常见服务和默认端口：</p><table tabindex="0"><thead><tr><th>端口</th><th>服务</th></tr></thead><tbody><tr><td>22</td><td>SSH</td></tr><tr><td>80</td><td>HTTP</td></tr><tr><td>443</td><td>HTTPS</td></tr><tr><td>3306</td><td>MySQL</td></tr><tr><td>6379</td><td>Redis</td></tr><tr><td>5432</td><td>PostgreSQL</td></tr></tbody></table><p>&quot;端口通不通&quot;的判断需要区分几个层面：本机服务是否监听、本机防火墙是否放行、云安全组是否放行、中间网络路由是否可达、对端防火墙是否拦截。<code>ss</code> 看本机监听，<code>telnet</code> 或 <code>nc</code> 从远端测试，分层查。</p><p>监听地址和端口的组合也很关键：</p><table tabindex="0"><thead><tr><th>监听方式</th><th>可访问范围</th></tr></thead><tbody><tr><td><code>127.0.0.1:8080</code></td><td>仅本机</td></tr><tr><td><code>0.0.0.0:8080</code></td><td>所有网卡、所有 IP</td></tr><tr><td><code>192.168.1.10:8080</code></td><td>仅 192.168.1.10 这个 IP</td></tr></tbody></table><p><code>ss -lntp</code> 输出中看到 <code>127.0.0.1:8080</code> 时，问题通常不在防火墙，而是服务配置本身就限制了只接收本机连接。</p><h2 id="六、osi-模型与排障顺序" tabindex="-1">六、OSI 模型与排障顺序 <a class="header-anchor" href="#六、osi-模型与排障顺序" aria-label="Permalink to &quot;六、OSI 模型与排障顺序&quot;">​</a></h2><p>OSI 七层模型在实际排障中不需要严格背诵。更有用的简化视图是按层次从下往上排查：</p><table tabindex="0"><thead><tr><th>排查步骤</th><th>要确认的事</th><th>对应命令</th></tr></thead><tbody><tr><td>1</td><td>网卡是否存在、是否有 IP</td><td><code>ip addr</code></td></tr><tr><td>2</td><td>路由是否正常</td><td><code>ip route</code></td></tr><tr><td>3</td><td>DNS 能否解析</td><td><code>getent hosts &lt;domain&gt;</code></td></tr><tr><td>4</td><td>本机端口是否监听</td><td><code>ss -lntp</code></td></tr><tr><td>5</td><td>TCP 能否连通</td><td><code>curl -v</code>、<code>nc -zv</code></td></tr><tr><td>6</td><td>应用是否正常响应</td><td>查看应用日志和返回内容</td></tr></tbody></table><p>这个从下往上的顺序，通常比一上来就抓包更快定位问题。</p><h2 id="七、tcp-三次握手" tabindex="-1">七、TCP 三次握手 <a class="header-anchor" href="#七、tcp-三次握手" aria-label="Permalink to &quot;七、TCP 三次握手&quot;">​</a></h2><p>TCP 在传输数据之前需要建立连接，这个过程叫三次握手。它本质上是一个双方互相确认收发能力的过程。</p><table tabindex="0"><thead><tr><th>步骤</th><th>方向</th><th>标志</th><th>含义</th></tr></thead><tbody><tr><td>1</td><td>客户端 → 服务端</td><td>SYN</td><td>&quot;我想和你建立连接&quot;</td></tr><tr><td>2</td><td>服务端 → 客户端</td><td>SYN-ACK</td><td>&quot;收到，我也准备好了&quot;</td></tr><tr><td>3</td><td>客户端 → 服务端</td><td>ACK</td><td>&quot;收到你的确认&quot;</td></tr></tbody></table><p>如果服务端端口没有监听，客户端发起 SYN 后服务端会回复 RST（复位），客户端收到 &quot;Connection refused&quot;。如果中间网络或防火墙丢弃了 SYN 包，客户端持续重发 SYN 但收不到任何回应，最终超时。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://10.0.0.1:80/</span></span></code></pre></div><p><code>Connection refused</code> 和 <code>Connection timed out</code> 是两个方向完全不同的信号：前者说明已经到达目标机器，但目标端口没有监听；后者说明网络层面的问题（路由不可达、防火墙丢弃、目标机器不存在等）。</p><p>UDP 没有三次握手，所以判断&quot;UDP 端口通不通&quot;没有 TCP 那么直观。DNS（53/UDP）、NTP 这类服务排查时经常需要检查应用层是否给出了响应，或直接抓包看 UDP 包有没有返回。</p>`,60)])])}const k=d(o,[["render",i]]);export{b as __pageData,k as default};
